import axios from 'axios';

const backendURL = 'http://localhost:3000/api/progress';

// Get authorization header
const getAuthHeader = () => {
    const token = localStorage.getItem('token');
    return token ? { Authorization: token } : {};
};

// Get user progress
export const getUserProgress = async (userId) => {
    try {
        const response = await axios.get(`${backendURL}/${userId}`, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Get user progress error:', error);
        throw error;
    }
};

// Update user progress
export const updateUserProgress = async (userId, progressData) => {
    try {
        const response = await axios.put(`${backendURL}/${userId}`, progressData, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Update user progress error:', error);
        throw error;
    }
};

// Update study streak
export const updateStudyStreak = async (userId, streakData) => {
    try {
        const response = await axios.put(`${backendURL}/${userId}/streak`, streakData, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Update study streak error:', error);
        throw error;
    }
};

// Update subject progress
export const updateSubjectProgress = async (userId, subjectId, progressData) => {
    try {
        const response = await axios.put(`${backendURL}/${userId}/subject/${subjectId}`, progressData, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Update subject progress error:', error);
        throw error;
    }
};

// Increment AI interactions
export const incrementAIInteractions = async (userId) => {
    try {
        const response = await axios.put(`${backendURL}/${userId}/ai`, {}, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Increment AI interactions error:', error);
        throw error;
    }
};
